INSERT INTO player_role_map VALUES(1,'2025-26','FC26','optimal','GK',50,6,'gk_sweeper','Build-Up',NULL,'[XI] Sweeper-keeper; best games as GK (8.7/8.2). Only position.');
INSERT INTO player_role_map VALUES(2,'2025-26','FC26','optimal','RB',87,32,'fb_att_wb','Support',NULL,'[XI] SEASON-REVISED 2026-07-04 재검증: 시즌 50경기 att_wb/Support 0.90 > wingback/Balanced 0.89 >> fullback(top5 밖). 공격진영 비중 33%로 정통 풀백보다 전진형. 문서도 fullback 기각(왕복형 wingback). 디뉴와 동일 처방 — 우측 폭 담당(맥긴 컷인 보상). Support 포커스로 복귀 규율 유지.');
INSERT INTO player_role_map VALUES(3,'2025-26','FC26','optimal','RCB',63,28,'cb_bpd','Build-Up',NULL,'[XI] SEASON-REVISED 2026-07-03: full-season RCB grid→cb_bpd/Aggressive 0.94 (best-game 0.88 — strengthened, NOT a bias artifact). Doc Defender/Defend REFUTED by both samples. Optimal focus Build-Up (ball-playing step-up) chosen over Aggressive to avoid gap-leaving on the back line; role:season keeps Aggressive as raw movement.');
INSERT INTO player_role_map VALUES(4,'2025-26','FC26','optimal','LCB',37,28,'cb_bpd','Build-Up',NULL,'[XI] Left ball-playing CB; carries/progresses from LCB.');
INSERT INTO player_role_map VALUES(5,'2025-26','FC26','optimal','LB',13,32,'fb_att_wb','Support',NULL,'[XI] SEASON-REVISED 2026-07-03: full-season LB grid→fb_att_wb/Support 0.91 (was fb_fullback/Versatile). Season shows Digne pushes MORE than best-game suggested (and more than Maatsen 0.86) — role SHAPE is attacking wingback; still first-choice LB by selection.');
INSERT INTO player_role_map VALUES(12,'2025-26','FC26','optimal','RDM',62,42,'dm_holding','Ball-Winning',NULL,'[XI] Deep screen/anchor of the double pivot (7.8/7.8). [SIDE CORRECTION 2026-07-02: measured avg-positions put Kamara RIGHT-of-centre (mean y=42.6 over 26 matches, incl. the 11-win streak); earlier LDM label came from lane-inverted heatmap text. Swapped with Onana.]');
INSERT INTO player_role_map VALUES(8,'2025-26','FC26','optimal','LDM',38,42,'dm_dlp','Roaming',NULL,'[XI] SEASON-REVISED 2026-07-03: full-season pivot grid→dm_dlp/Roaming 0.62 (best-game dm_boxcrasher fell out — surging/heading games overweighted the sample; season avg depth ~44 = deep roamer). Doc Holding/Roaming 0.57 near. Kamara keeps the screen; Onana roams.');
INSERT INTO player_role_map VALUES(13,'2025-26','FC26','optimal','CAM',15,64,'cam_playmaker','Roaming',NULL,'[XI] SEASON-REVISED 2026-07-03: full-season primary = CAM (21 matches/1759min, avg 7.1 ≥ LW 6.91/13min-share); CAM grid→cam_playmaker/Roaming 0.74 clean. Prior best-game optimal (LW peaks 8.84/8.46) was CEILING bias; season-average says central 10 is his base. Matches doc + role:season.');
INSERT INTO player_role_map VALUES(14,'2025-26','FC26','optimal','LW',50,66,'w_insidefwd','Attack',NULL,'[XI] SEASON-REVISED 2026-07-03: full-season primary = LW/AML (21 matches) >> CAM (3 matches); inverted creator on the left. Prior optimal (central 10, peak 9.4) was a single-game ceiling; season says his base is left. Inside Forward/Attack for the cut-in creator profile (season closest w_wideplm/Build-Up 0.71).');
INSERT INTO player_role_map VALUES(10,'2025-26','FC26','optimal','RM',85,64,'wm_insidefwd','Balanced',NULL,'[XI] SEASON-REVISED 2026-07-04: full-season RM grid→wm_insidefwd/Balanced 0.80(명확한 1위). 안으로 컷인, 폭은 캐시. [2026-07-05 REVERT: 역할 숙련도(와이드미드) 기반 변경을 되돌림 — 숙련도의 게임 내 성능 영향 크기를 먼저 규명한 뒤 재검토. 현재는 실측 최적 유지.]');
INSERT INTO player_role_map VALUES(16,'2025-26','FC26','optimal','ST',50,87,'st_advanced','Versatile',NULL,'[XI] Lone ST; 8.7/8.5 in wins, channel runs + in-behind.');
INSERT INTO player_role_map VALUES(6,'2025-26','FC26','optimal','LB',NULL,NULL,'fb_wingback','Balanced',NULL,'[bench] SEASON-REVISED 2026-07-03: full-season LB grid→fb_wingback/Balanced 0.86 (best-game fb_att_wb/Support 0.85 fell out of season top — attacking outings overweighted the best-game sample). Disciplined two-way wingback, matches doc.');
INSERT INTO player_role_map VALUES(9,'2025-26','FC26','optimal','LDM',NULL,NULL,'dm_dlp','Build-Up',NULL,'[bench] DATA KEY: optimal DEEPER pivot (EL final 8.4) NOT the No.10; premier deep-mid rotation.');
INSERT INTO player_role_map VALUES(7,'2025-26','FC26','optimal','LCB',NULL,NULL,'cb_bpd','Build-Up',NULL,'[bench] SEASON-REVISED 2026-07-04: 시즌 28경기 cb_bpd/Aggressive 0.78 > cb_defender(top밖) — 파우·콘사와 동일 볼플레잉 프로필(단 0.78로 다소 약함). cb_defender→cb_bpd/Build-Up 통일. 락다운 게임 한정 cb_defender 대안 가능.');
