INSERT INTO player_role_map VALUES(23,'2023-24','FC26','measured','RW',61.20000000000000284,65.29999999999999716,NULL,NULL,'222734237X115252112311010','23/24 top5 균등가중 통합그리드(219 히트포인트). 중심 (61.2,65.3) 툴좌표 = 우측 전진이나 터치라인 아님(안으로 좁힘).');
INSERT INTO player_role_map VALUES(23,'2023-24','FC26','optimal','RW',85,64,'w_wideplm','Build-Up',NULL,'실측 슬롯 x85 커널 코사인: w_wideplm/Build-Up 0.81 > wm_insidefwd/Balanced 0.79 > w_insidefwd/Roaming 0.75. 현 4-2-3-1 우측 등가역할=wm_insidefwd/Balanced. 서사(''다이렉트 스피드 위어'')보다 터치가 involved·인버티드 — off-ball 침투는 터치맵 미포착(실측>서사 캐비엇). 실측 최근접 현 선수: 아데예미 0.87(둘 다 인사이드 드리프트).');
INSERT INTO player_role_map VALUES(24,'2024-25','FC26','measured','ST',47.5,61.5,NULL,NULL,'129313785316X311222111210','24/25 top5 균등가중 통합그리드(200 히트포인트). 중심 (47.5,61.5) = 중앙 전진 스트라이커.');
INSERT INTO player_role_map VALUES(24,'2024-25','FC26','optimal','ST',50,87,'st_advanced','Attack',NULL,'중앙 ST 풋프린트는 변별력 약함(실측 그리드 코사인은 왓킨스조차 st_false9 최고로 뽑음 — st_advanced 커널이 과전진). 선수간 실측 유사도: 기라시 0.95·왓킨스 0.90·브로베이 0.90. ''듀란형''은 히트맵이 아니라 능력치(PAC85+·PHY80+·파워/롱슛·인비하인드)로 정의. optimal 역할은 에메리 실사용(임팩트 서브·다이렉트·인비하인드·중앙고정)에 따라 st_advanced/Attack 지정.');
